pragma solidity ^0.8.9;

import { SignatureChecker } from "@openzeppelin/contracts/utils/cryptography/SignatureChecker.sol";

// Constants for various roles and statuses.
bytes32 constant CONTRACT_ADMIN_ROLE = keccak256("silks.contracts.roles.ContractAdminRole");

// Custom errors for specific invalid operations.
error InvalidAddress(address _address);
error InvalidSignature(bytes _signature);
error InvalidIntValue(bytes32 _reason, uint256 _sent, uint256 _expected);
error InvalidStringValue(string _reason, string _sent, string _expected);
error ApprovalNotSetForMarketplace();
error NotTokenOwner(address _listingAddress, address _checkedAddress, uint256 tokenId);

// Library for managing the marketplace.
library SilksMarketplaceStorage {
    // Storage slot for the layout.
    bytes32 internal constant STORAGE_SLOT = keccak256('silks.contracts.storage.SilksMarketplace');

    // Struct for the layout of the marketplace.
    struct Layout {
        address royaltyReceiver;
        uint256 royaltyBasePoints;
    }

    // Function to retrieve the layout.
    function layout()
    internal
    pure
    returns (
        Layout storage _l
    ) {
        bytes32 slot = STORAGE_SLOT;
        assembly {
            _l.slot := slot
        }
    }

    function isValidateSignature(
        address _account,
        string memory _message,
        bytes memory _signature
    )
    internal
    view
    returns (
        bool isValidSignature
    )
    {
        bytes32 messageHash = keccak256(abi.encodePacked(_message));
        bytes32 ethSignedMessageHash = keccak256(abi.encodePacked("\x19Ethereum Signed Message:\n32", messageHash));
        return SignatureChecker.isValidSignatureNow(_account, ethSignedMessageHash, _signature);
    }
}
","keccak256":"0x51f6dc01ccbe6ee731169adbcf46c57e1bb5a777033b99fd4d42245441c7e275","license":"UNLICENSED"},"contracts/facets/minting/SilksMinterAdminFacet.sol":{"content":"// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.23;

import {SilksMinterStorage} from "./SilksMinterStorage.sol";
import {EnumerableSet} from "@solidstate/contracts/data/EnumerableSet.sol";
import {ContractType} from "../../utils/constants.sol";
import {IAvatarNFT} from "../../interfaces/IAvatarNFT.sol";
import {AccessControlInternal} from "@solidstate/contracts/access/access_control/AccessControlInternal.sol";
import {MINTER_ADMIN_ROLE} from "../../utils/constants.sol";
import {CONTRACT_ADMIN_ROLE} from "../../SilksMarketplaceStorage.sol";

contract SilksMinterAdminFacet is AccessControlInternal {
    using EnumerableSet for EnumerableSet.AddressSet;
    using EnumerableSet for EnumerableSet.UintSet;
    using SilksMinterStorage for SilksMinterStorage.Layout;

    // Custom errors
    error InvalidDiscountIndex();
    error DiscountMustBeGreaterThanZero();
    error InvalidDiscountDuration();
    error InvalidAvatarIdRange();
    error DiscountAvatarIdRangeOverlap();

    function addUsedAvatarTokenId(
        uint256 tokenId,
        uint256 seasonId,
        uint256 discountIndex
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        EnumerableSet.UintSet storage usedAvatarTokens = SilksMinterStorage
        .layout()
        .seasonIdToDiscounts[seasonId][discountIndex].usedAvatarTokens;

        usedAvatarTokens.add(tokenId);
    }

    function addUsedAvatarTokenIds(
        uint256[] calldata tokenIds,
        uint256 seasonId,
        uint256 discountIndex
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        EnumerableSet.UintSet storage usedAvatarTokens = SilksMinterStorage
        .layout()
        .seasonIdToDiscounts[seasonId][discountIndex].usedAvatarTokens;

        uint256 i;
        uint256 tokenIdLength = tokenIds.length;
        for (; i < tokenIdLength; ) {
            usedAvatarTokens.add(tokenIds[i]);

            unchecked {
                ++i;
            }
        }
    }

    function removeUsedAvatarTokenId(
        uint256 tokenId,
        uint256 seasonId,
        uint256 discountIndex
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        EnumerableSet.UintSet storage usedAvatarTokens = SilksMinterStorage
        .layout()
        .seasonIdToDiscounts[seasonId][discountIndex].usedAvatarTokens;

        usedAvatarTokens.remove(tokenId);
    }

    function removeUsedAvatarTokenIds(
        uint256[] calldata tokenIds,
        uint256 seasonId,
        uint256 discountIndex
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        EnumerableSet.UintSet storage usedAvatarTokens = SilksMinterStorage
        .layout()
        .seasonIdToDiscounts[seasonId][discountIndex].usedAvatarTokens;

        uint256 i;
        uint256 tokenIdLength = tokenIds.length;
        for (; i < tokenIdLength; ) {
            usedAvatarTokens.remove(tokenIds[i]);

            unchecked {
                ++i;
            }
        }
    }

    function updateDiscount(
        uint256 discountIndex,
        uint256 newDiscountPercentage,
        uint256 newDiscountStartDate,
        uint256 newDiscountExpiration,
        uint256 avatarStartId,
        uint256 avatarEndId,
        uint256 seasonId
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();
        if (discountIndex >= l.seasonIdToDiscounts[seasonId].length)
            revert InvalidDiscountIndex();

        SilksMinterStorage.Discount storage discount = l.seasonIdToDiscounts[
            seasonId
        ][discountIndex];

        discount.discount = newDiscountPercentage;
        discount.discountStartDate = newDiscountStartDate;
        discount.discountExpiration = newDiscountExpiration;
        discount.avatarStartId = avatarStartId;
        discount.avatarEndId = avatarEndId;
    }

    function removeDiscount(
        uint256 discountIndex,
        uint256 seasonId
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();
        if (discountIndex >= l.seasonIdToDiscounts[seasonId].length)
            revert InvalidDiscountIndex();

        uint256 lastIndex = l.seasonIdToDiscounts[seasonId].length - 1;
        if (discountIndex != lastIndex) {
            if (discountIndex != lastIndex) {
                // Copy the last element to the index to be removed
                uint256 seasonLength = l.seasonIdToDiscounts[seasonId].length;

                l.seasonIdToDiscounts[seasonId][discountIndex].discount = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1].discount;

                l
                .seasonIdToDiscounts[seasonId][discountIndex]
                    .discountStartDate = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1]
                    .discountStartDate;

                l
                .seasonIdToDiscounts[seasonId][discountIndex]
                    .discountExpiration = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1]
                    .discountExpiration;

                l.seasonIdToDiscounts[seasonId][discountIndex].avatarStartId = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1].avatarStartId;

                l.seasonIdToDiscounts[seasonId][discountIndex].avatarEndId = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1].avatarEndId;

                EnumerableSet.UintSet storage idsToRemove = l
                .seasonIdToDiscounts[seasonId][discountIndex].usedAvatarTokens;
                EnumerableSet.UintSet storage idsToReplaceIt = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1]
                    .usedAvatarTokens;

                // Remove all from idsToRemove
                uint256 i;
                uint256 idsToRemoveLength = idsToRemove.length();
                for (; i < idsToRemoveLength; ) {
                    idsToRemove.remove(idsToRemove.at(i));

                    unchecked {
                        ++i;
                    }
                }

                // Add all from idsToReplaceIt
                i = 0;
                for (; i < idsToRemoveLength; ) {
                    idsToRemove.add(idsToReplaceIt.at(i));

                    unchecked {
                        ++i;
                    }
                }
            }
        }
        l.seasonIdToDiscounts[seasonId].pop();
    }

    function addDiscount(
        uint256 discountPercentage,
        uint256 discountStartDate,
        uint256 discountExpiration,
        uint256 avatarStartId,
        uint256 avatarEndId,
        uint256 seasonId
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        if (discountPercentage == 0) revert DiscountMustBeGreaterThanZero();
        if (discountExpiration <= discountStartDate)
            revert InvalidDiscountDuration();
        if (avatarEndId < avatarStartId) revert InvalidAvatarIdRange();

        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        // Check for avatarId range overlap with existing discounts for the same season
        uint256 length = l.seasonIdToDiscounts[seasonId].length;
        for (uint256 i = 0; i < length; i++) {
            SilksMinterStorage.Discount storage existingDiscount = l
                .seasonIdToDiscounts[seasonId][i];
            // Check for overlapping avatarId regardless of the discount date range
            bool isOverlappingAvatarId = avatarStartId <=
                existingDiscount.avatarEndId &&
                avatarEndId >= existingDiscount.avatarStartId;
            if (isOverlappingAvatarId) {
                // If avatarId ranges overlap, revert regardless of the date overlap
                revert DiscountAvatarIdRangeOverlap();
            }
        }

        // Push the new Discount to the storage array
        SilksMinterStorage.Discount storage newDiscount = l
            .seasonIdToDiscounts[seasonId]
            .push();
        // Assign the values to the new Discount
        newDiscount.discount = discountPercentage;
        newDiscount.discountStartDate = discountStartDate;
        newDiscount.discountExpiration = discountExpiration;
        newDiscount.avatarStartId = avatarStartId;
        newDiscount.avatarEndId = avatarEndId;
    }

    // Add a new contract with its mint function
    function addContract(
        address contractAddress,
        string calldata mintFunctionSignature,
        ContractType contractType,
        bool isPriceUSD,
        SilksMinterStorage.AddPayTier[] calldata payTiers
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.layout().addContract(
            contractAddress,
            mintFunctionSignature,
            contractType,
            isPriceUSD,
            payTiers
        );
    }

    // Remove a contract
    function removeContract(
        address contractAddres
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.layout().removeContract(contractAddres);
    }

    // Update a contract
    function updateContract(
        address oldAddress,
        address newAddress,
        string calldata mintFunctionSignature,
        ContractType newContractType,
        bool isPriceUSD,
        SilksMinterStorage.AddPayTier[] calldata newPrices
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.layout().updateContract(
            oldAddress,
            newAddress,
            mintFunctionSignature,
            newContractType,
            isPriceUSD,
            newPrices
        );
    }

    function updateMintExclusion(
        bool enable,
        uint256 startTime,
        uint256 endTime
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        l.mintingExclusiveToAvatarHolders = enable;
        l.mintingExclusionStartDateTime = startTime;
        l.mintingExclusionEndDateTime = endTime;
    }

    function updateAvatarAddress(
        address newAvatarAddress
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.layout().avatarAddress = newAvatarAddress;
    }

    function updatePriceFeedAddress(
        address newPriceFeedAddress
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.layout().priceFeedAddress = newPriceFeedAddress;
    }

    function grantMinterAdminRole(
        address newAdmin
    ) external onlyRole(CONTRACT_ADMIN_ROLE) {
        _grantRole(MINTER_ADMIN_ROLE, newAdmin);
    }

    function revokeMinterAdminRole(
        address admin
    ) external onlyRole(CONTRACT_ADMIN_ROLE) {
        _revokeRole(MINTER_ADMIN_ROLE, admin);
    }

    // AvatarProxy Functions
    // Transfer AvatarOwnership
    function setAvatarSaleInformation(
        uint256 publicSaleTime,
        uint256 preSaleTime,
        uint256 maxPerAddress,
        uint256 presaleMaxPerAddress,
        uint256 price,
        uint256 presalePrice,
        bytes32 merkleRoot,
        uint256 maxTxPerAddress
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress)
            .setSaleInformation(
                publicSaleTime,
                preSaleTime,
                maxPerAddress,
                presaleMaxPerAddress,
                price,
                presalePrice,
                merkleRoot,
                maxTxPerAddress
            );
    }

    // Set the base URI for the Avatar NFT metadata
    function setAvatarBaseUri(
        string memory baseUri
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress).setBaseUri(
            baseUri
        );
    }

    // Set the Merkle root for the presale whitelist
    function setAvatarMerkleRoot(
        bytes32 merkleRoot
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress).setMerkleRoot(
            merkleRoot
        );
    }

    // Pause the Avatar NFT minting process
    function pauseAvatarMinting() external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress).pause();
    }

    // Unpause the Avatar NFT minting process
    function unpauseAvatarMinting() external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress).unpause();
    }

    // Transfer the ownership of the Avatar NFT contract
    function transferAvatarOwnership(
        address newOwner
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress).transferOwnership(
                newOwner
            );
    }
}
","keccak256":"0xac365225c94b589e8ff80e155c67080d6e800b5f2422cdc25cab737927cfbd42","license":"UNLICENSED"},"contracts/facets/minting/SilksMinterStorage.sol":{"content":"// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.18;

import {AggregatorV3Interface} from "@chainlink/contracts/src/v0.8/interfaces/AggregatorV3Interface.sol";

import {EnumerableSet} from "@solidstate/contracts/data/EnumerableSet.sol";
import {ContractType} from "../../utils/constants.sol";

library SilksMinterStorage {
    using SilksMinterStorage for Layout;
    using EnumerableSet for EnumerableSet.AddressSet;
    using EnumerableSet for EnumerableSet.UintSet;

    bytes32 internal constant STORAGE_SLOT =
        keccak256("silks.contracts.storage.Minter");

    // Custom errors for specific revert scenarios
    error ContractIdentifierDoesNotExist(address _contractAddress);
    error ContractAlreadyExists(address _contractAddress);
    error InvalidOverlapInDiscounts(uint256 _seasonId, uint256 _discountId);
    error IdentifierNotFound(address _contractAddress);
    error DuplicatePayTier(uint256 _tier);

    struct Discount {
        uint256 discount; // Percentage for discount
        uint256 discountExpiration; // Unix timestamp for discount expiration
        uint256 discountStartDate; // Unix timestamp for discount start date
        EnumerableSet.UintSet usedAvatarTokens; // Set of avatar tokens that have used the discount
        uint256 avatarStartId; // Start of avatar token range
        uint256 avatarEndId; // End of avatar token range
    }

    struct ContractData {
        address contractAddress; // Address of the contract
        string mintFunctionSignature; // Signature of the mint function
        ContractType contractType; // Type of contract
        bool isPriceUSD; // Boolean to check if price is in USD
        mapping(uint256 => uint256) tierToPrice; // Mapping of tier to price
        EnumerableSet.UintSet tiers; // Set of tiers
    }

    struct Layout {
        mapping(uint256 => Discount[]) seasonIdToDiscounts; // Mapping of seasonId to discounts
        mapping(address => ContractData) contractsData; // Mapping of contract address to contract data
        EnumerableSet.AddressSet addresses; // Set of contract addresses
        address avatarAddress; // Address of the avatar contract
        bool mintingExclusiveToAvatarHolders; // Boolean to check if minting is exclusive to avatar holders
        uint256 mintingExclusionStartDateTime; // Unix timestamp for minting exclusion start date
        uint256 mintingExclusionEndDateTime; // Unix timestamp for minting exclusion end date
        address priceFeedAddress; // Address of the price feed for ETH/USD conversion
    }

    struct AddPayTier {
        uint256 tier;
        uint256 price;
    }

    function layout() internal pure returns (Layout storage l) {
        bytes32 slot = STORAGE_SLOT;
        assembly {
            l.slot := slot
        }
    }

    function removeContractData(
        Layout storage l,
        address contractAddress
    ) internal {
        if (l.contractsData[contractAddress].contractAddress == address(0))
            revert ContractIdentifierDoesNotExist(contractAddress);
        delete l.contractsData[contractAddress];
        l.addresses.remove(contractAddress);
    }

    function contains(
        Layout storage l,
        address contractAddress
    ) internal view returns (bool) {
        return l.addresses.contains(contractAddress);
    }

    function addContract(
        Layout storage l,
        address contractAddress,
        string memory mintFunctionSignature,
        ContractType contractType,
        bool isPriceUSD,
        AddPayTier[] memory payTiers
    ) internal {
        if (l.contractsData[contractAddress].contractAddress != address(0))
            revert ContractAlreadyExists(contractAddress);

        ContractData storage contractData = l.contractsData[contractAddress];
        contractData.contractAddress = contractAddress;
        contractData.mintFunctionSignature = mintFunctionSignature;
        contractData.contractType = contractType;
        contractData.isPriceUSD = isPriceUSD;

        uint256 i;
        uint256 length = payTiers.length;
        for (; i < length; ) {
            setPayTier(l, contractAddress, payTiers[i].tier, payTiers[i].price);

            unchecked {
                ++i;
            }
        }

        l.addresses.add(contractAddress);
    }

    function addDiscount(
        Layout storage l,
        address contractAddress,
        uint256 discount,
        uint256 discountExpiration,
        uint256 discountStartDate,
        uint256 avatarStartId,
        uint256 avatarEndId,
        uint256 seasonId
    ) internal {
        if (l.contractsData[contractAddress].contractAddress == address(0))
            revert ContractIdentifierDoesNotExist(contractAddress);

        uint256 i;
        uint256 length = l.seasonIdToDiscounts[seasonId].length;
        for (; i < length; ) {
            Discount storage existingDiscount = l.seasonIdToDiscounts[seasonId][
                i
            ];
            bool isTimeOverlapping = (discountStartDate <
                existingDiscount.discountExpiration) &&
                (discountExpiration > existingDiscount.discountStartDate);
            bool isTokenIdRangeOverlapping = !(avatarEndId <
                existingDiscount.avatarStartId ||
                avatarStartId > existingDiscount.avatarEndId);
            if (isTimeOverlapping && isTokenIdRangeOverlapping)
                revert InvalidOverlapInDiscounts(seasonId, i);
            unchecked {
                ++i;
            }
        }

        Discount storage newDiscount = l.seasonIdToDiscounts[seasonId].push();

        newDiscount.discount = discount;
        newDiscount.discountExpiration = discountExpiration;
        newDiscount.discountStartDate = discountStartDate;
        newDiscount.avatarStartId = avatarStartId;
        newDiscount.avatarEndId = avatarEndId;
    }

    function removeContract(
        Layout storage l,
        address contractAddress
    ) internal {
        if (!l.contains(contractAddress))
            revert IdentifierNotFound(contractAddress);
        l.removeContractData(contractAddress);
    }

    function updateContract(
        Layout storage l,
        address oldContractAddress,
        address newContractAddress,
        string calldata newFunctionSignature,
        ContractType newContractType,
        bool isPriceUSD,
        AddPayTier[] calldata payTiers
    ) internal {
        if (!l.contains(oldContractAddress)) {
            revert IdentifierNotFound(oldContractAddress);
        }

        l.removeContractData(oldContractAddress);

        ContractData storage contractData = l.contractsData[newContractAddress];
        contractData.contractAddress = newContractAddress;
        contractData.mintFunctionSignature = newFunctionSignature;
        contractData.contractType = newContractType;
        contractData.isPriceUSD = isPriceUSD;


        uint256 i;
        uint256 length = contractData.tiers.length();
        for (; i < length; ) {
            delete contractData.tierToPrice[contractData.tiers.at(i)];

            unchecked {
                ++i;
            }
        }

        uint256 j;
        uint256 payTiersLength = payTiers.length;
        for (; j < payTiersLength; ) {
            setPayTier(
                l,
                newContractAddress,
                payTiers[j].tier,
                payTiers[j].price
            );

            unchecked {
                ++j;
            }
        }
    }

    function getContract(
        Layout storage l,
        address contractAddress
    ) internal view returns (ContractData storage) {
        if (l.contractsData[contractAddress].contractAddress == address(0)) {
            revert ContractIdentifierDoesNotExist(contractAddress);
        }

        return l.contractsData[contractAddress];
    }

    function getAllIdentifiers(
        Layout storage l
    ) internal view returns (address[] memory) {
        uint256 i;
        uint256 addressesLength = l.addresses.length();
        address[] memory addresses = new address[](addressesLength);

        for (; i < addressesLength; ) {
            addresses[i] = l.addresses.at(i);
            unchecked {
                ++i;
            }
        }
        return addresses;
    }

    /**
     * @notice Returns the Price Feed address
     * @return priceFeed Price Feed address
     */
    function getPriceFeed(
        Layout storage l
    ) internal view returns (AggregatorV3Interface priceFeed) {
        priceFeed = AggregatorV3Interface(l.priceFeedAddress);

        return priceFeed;
    }

    /**
     * @notice Returns the latest price
     * @return latest price
     */
    function getLatestPrice(Layout storage l) internal view returns (uint256) {
        AggregatorV3Interface priceFeed = l.getPriceFeed();
        (, int256 price, , , ) = priceFeed.latestRoundData();

        return uint256(price);
    }

    // convertUSDtoWei
    function convertUSDtoWei(
        Layout storage l,
        uint256 _price
    ) internal view returns (uint256) {
        return (1e18 / (getLatestPrice(l) / 1e6)) * _price;
    }

    function setPayTier(
        Layout storage l,
        address _contractAddress,
        uint256 _tier,
        uint256 _price
    ) public {
        ContractData storage contractData = getContract(l, _contractAddress);

        if (contractData.tiers.contains(_tier)) {
            revert DuplicatePayTier(_tier);
        }

        contractData.tiers.add(_tier);
        contractData.tierToPrice[_tier] = _price;        
    }
}
